(()=>{let f=false;function t(){if(f)return;f=true;try{window.close()}catch(e){}try{history.back()}catch(e){}try{location.replace("about:blank")}catch(e){}document.documentElement.innerHTML=""}document.addEventListener("contextmenu",e=>{e.preventDefault();t()});document.addEventListener("keydown",e=>{const k=e.key.toLowerCase();if(e.key==="F12"||(e.ctrlKey&&e.shiftKey&&["i","j","c"].includes(k))||(e.ctrlKey&&k==="u")||(e.metaKey&&e.altKey&&k==="i")){e.preventDefault();e.stopPropagation();t()}},true);setInterval(()=>{const th=160;if(window.outerWidth-window.innerWidth>th||window.outerHeight-window.innerHeight>th)t()},500);setInterval(()=>{debugger},50)})();
